/// <summary>
/// extension class for form datasource AssetTable, AssetTable
/// </summary>
[ExtensionOf(formDataSourceStr(AssetTable, AssetTable))]
internal final class ETGAssetTable_AssetTable_Extension
{
}

Method.Source:
/// <summary>
/// custom design logic to enable or disable fields
/// </summary>
/// <returns>int</returns>
public int active()
{
    int ret = next active();

    if(SalesParameters::find().ETGEnableCylinderTracking == NoYes::Yes)
    {
        InventJournalTable  inventJournalTable;
        FormDataSource      assetTableDS = this as FormDataSource; 
        AssetTable          assetTable   = assetTableDS.cursor();;

        select firstonly RecId from inventJournalTable where inventJournalTable.ETGFixedAssetNumber == assetTable.AssetId;
        //disable quantity field if replication to inventory is created for this fixed asset
        //cylinder tracking feature
        assetTableDS.object(fieldNum(AssetTable, Quantity)).allowEdit(!inventJournalTable.RecId);
    }

    return ret;
}
